import{_ as t,H as a,f as i,i as o}from"./chunks/framework.DSVXGFvA.js";const u=JSON.parse('{"title":"NetGet Registration","description":"","frontmatter":{},"headers":[],"relativePath":"netget-registration.md","filePath":"netget-registration.md"}'),s={name:"netget-registration.md"};function d(n,e,r,l,c,p){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="netget-registration" tabindex="-1">NetGet Registration <a class="header-anchor" href="#netget-registration" aria-label="Permalink to &quot;NetGet Registration&quot;">​</a></h1><p><code>monad.ai</code> treats NetGet as the local gateway and registry. When a monad starts, it reports itself to <code>local.netget</code> through <code>POST /apps/report</code> and keeps that entry fresh with a heartbeat.</p><p>The registration is intentionally internal-first:</p><ul><li><code>kind: &quot;monad&quot;</code> marks the app as a monad citizen of NetGet.</li><li><code>host</code> defaults to <code>127.0.0.1</code>; monads should not expose LAN/WAN ports directly.</li><li><code>metadata.monadName</code>, <code>metadata.monadId</code>, <code>metadata.namespace</code>, and <code>metadata.capabilities</code> make the entry usable by GUI discovery.</li><li><code>exposure.visibility</code> defaults to <code>loopback</code>.</li><li>lifecycle support is advertised, but NetGet policy decides which controls are actually allowed.</li></ul><p>The focused build guard is:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test:netget</span></span></code></pre></div><p><code>npm run build</code> runs that guard through <code>prebuild</code>.</p>',7)])])}const g=t(s,[["render",d]]);export{u as __pageData,g as default};
